    43	      const lines = lsofOut.split("\n").filter((l) => l.trim());
    44	      // Skip the header line (starts with COMMAND)
    45	      const dataLines = lines.filter((l) => !l.startsWith("COMMAND"));
    46	      if (dataLines.length > 0) {
    47	        // Parse first data line: COMMAND PID USER ...
    48	        const parts = dataLines[0].split(/\s+/);
    49	        const proc = parts[0] || "unknown";
    50	        const pid = parseInt(parts[1], 10) || null;
