const assert = require('node:assert');
const childProcess = require('node:child_process');
const { EventEmitter } = require('node:events');
const fs = require('node:fs');
const os = require('node:os');
const path = require('node:path');

const repo = '/workspace/NemoClaw';
const sentinel = 'nvapi-argv-exposure-sentinel';
const commands = [];

const tmpHome = fs.mkdtempSync(path.join(os.tmpdir(), 'nemoclaw-repro-home-'));
process.env.HOME = tmpHome;
process.env.NVIDIA_API_KEY = sentinel;
process.env.NEMOCLAW_NON_INTERACTIVE = '1';
process.env.NEMOCLAW_PROVIDER = 'cloud';
process.env.NEMOCLAW_SANDBOX_NAME = 'argv-repro';
process.env.NEMOCLAW_POLICY_MODE = 'skip';
process.env.NO_COLOR = '1';

function record(command, args) {
  commands.push([command, ...(args || [])].join(' '));
}

childProcess.execSync = (cmd) => {
  record('execSync', [cmd]);
  if (cmd.includes('docker info')) return Buffer.from('Server Version: mock\n');
  if (cmd.includes('command -v openshell')) return Buffer.from('/tmp/mock-openshell\n');
  if (cmd.includes('command -v lsof')) return Buffer.from('');
  if (cmd.includes('openshell --version') || cmd.includes('openshell -V')) return Buffer.from('openshell 0.0.12\n');
  if (cmd.includes('openshell gateway info')) return Buffer.from('');
  if (cmd.includes('openshell status')) return Buffer.from('Connected\n');
  if (cmd.includes('nvidia-smi') || cmd.includes('system_profiler') || cmd.includes('sysctl')) return Buffer.from('');
  if (cmd.includes('openshell sandbox get')) return Buffer.from('argv-repro\n');
  return Buffer.from('');
};

childProcess.spawnSync = (command, args = []) => {
  record('spawnSync', [command, ...args]);
  return { status: 0, stdout: '', stderr: '' };
};

childProcess.spawn = (command, args = []) => {
  record('spawn', [command, ...args]);
  const proc = new EventEmitter();
  proc.stdout = new EventEmitter();
  proc.stderr = new EventEmitter();
  process.nextTick(() => {
    proc.stdout.emit('data', Buffer.from('Created sandbox: argv-repro\n'));
    proc.emit('close', 0);
  });
  return proc;
};

const { onboard } = require(path.join(repo, 'bin/lib/onboard'));

onboard({ nonInteractive: true })
  .then(() => {
    const leakedCommands = commands.filter((cmd) => cmd.includes(sentinel));
    fs.rmSync(tmpHome, { recursive: true, force: true });
    assert.strictEqual(
      leakedCommands.length,
      0,
      `secret appeared in process argv command(s):\n${leakedCommands.join('\n')}`,
    );
  })
  .catch((err) => {
    fs.rmSync(tmpHome, { recursive: true, force: true });
    console.error(err && err.stack ? err.stack : err);
    process.exit(1);
  });
